import React, { useState, useEffect } from "react";
import { signInWithPopup } from "firebase/auth";
import { doc, getDoc, setDoc } from "firebase/firestore";
import { auth, db, googleProvider } from "../firebase/config";
import { useNavigate } from "react-router-dom";
import neuLogo from "../assets/neu-library-logo.png";
import scheduleImg from "../assets/neu-library-sched.jpg";

const ALLOWED_DOMAIN = "neu.edu.ph";
const NEU_LIBRARY_IMG = "https://lookaside.fbsbx.com/lookaside/crawler/media/?media_id=862977945973327";
const SCHEDULE_IMG = scheduleImg;

export default function LoginPage() {
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [showSchedule, setShowSchedule] = useState(false);
  const [imgLoaded, setImgLoaded] = useState(false);
  const [time, setTime] = useState(new Date());
  const navigate = useNavigate();

  useEffect(() => {
    const t = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(t);
  }, []);

  const handleSignIn = async () => {
    setError("");
    setLoading(true);

    try {
      const result = await signInWithPopup(auth, googleProvider);
      const user = result.user;

      if (!user.email.endsWith("@" + ALLOWED_DOMAIN)) {
        await auth.signOut();
        setError("Only @" + ALLOWED_DOMAIN + " emails are allowed.");
        setLoading(false);
        return;
      }

      const ref = doc(db, "users", user.uid);
      const snap = await getDoc(ref);

      if (!snap.exists()) {
        await setDoc(ref, {
          uid: user.uid,
          email: user.email,
          fullName: user.displayName || "",
          role: "user",
          userType: "",
          college_office: "",
          isSetupComplete: false,
          isBlocked: false,
          createdAt: new Date(),
        });

        navigate("/onboarding");
      } else {
        const data = snap.data();

        if (data.isBlocked) {
          await auth.signOut();
          setError("Access Denied. Please contact the Library Admin.");
          setLoading(false);
          return;
        }

        if (!data.isSetupComplete) navigate("/onboarding");
        else if (data.role === "admin") navigate("/admin");
        else navigate("/checkin");
      }
    } catch {
      setError("Sign-in failed. Please try again.");
    }

    setLoading(false);
  };

  const timeStr = time.toLocaleTimeString("en-US", {
    hour: "2-digit",
    minute: "2-digit",
  });

  const dateStr = time.toLocaleDateString("en-US", {
    weekday: "long",
    month: "long",
    day: "numeric",
    year: "numeric",
  });

  return (
    <div style={s.page}>
      {/* LEFT PANEL */}
      <div style={s.hero}>
        <img
          src={NEU_LIBRARY_IMG}
          alt="NEU Library"
          style={{ ...s.heroImg, opacity: imgLoaded ? 1 : 0 }}
          onLoad={() => setImgLoaded(true)}
          onError={(e) => (e.target.style.display = "none")}
        />

        <div style={s.heroOverlay} />

        <div style={s.heroBadge}>
          <div style={s.badgeDot} />
          <span>Library Open Today</span>
        </div>

        <div style={s.clock}>
          <p style={s.clockTime}>{timeStr}</p>
          <p style={s.clockDate}>{dateStr}</p>
        </div>

        <div style={s.heroBottom}>
          <div style={s.heroCard}>
            <span style={s.heroCardIcon}>📚</span>
            <div>
              <p style={s.heroCardNum}>50,000+</p>
              <p style={s.heroCardLabel}>Books & Journals</p>
            </div>
          </div>

          <div style={s.heroCard}>
            <span style={s.heroCardIcon}>🎓</span>
            <div>
              <p style={s.heroCardNum}>22</p>
              <p style={s.heroCardLabel}>Colleges & Offices</p>
            </div>
          </div>

          <button style={s.schedBtn} onClick={() => setShowSchedule(true)}>
            📅 View Schedule
          </button>
        </div>

        <div style={s.stripe} />
      </div>

      {/* RIGHT LOGIN */}
      <div style={s.formSide}>
        <div style={s.formWrap}>
          <div style={s.logoRow}>
            <div style={s.logoBox}>
              <img
                src={neuLogo}
                alt="NEU Logo"
                style={{
                  width: "100%",
                  height: "100%",
                  objectFit: "cover",
                  borderRadius: 14,
                }}
              />
            </div>

            <div>
              <p style={s.logoLabel}>NEW ERA UNIVERSITY</p>
              <p style={s.logoSub}>Library System</p>
            </div>
          </div>

          <h1 style={s.title}>Welcome Back</h1>

          <p style={s.subtitle}>
            Sign in with your institutional email to access the library visitor
            log system.
          </p>

          {error && (
            <div style={s.errorBox}>
              <span>⚠️</span>
              <span>{error}</span>
            </div>
          )}

          <button
            style={{ ...s.googleBtn, ...(loading ? s.googleBtnLoading : {}) }}
            onClick={handleSignIn}
            disabled={loading}
          >
            <span>{loading ? "Signing in..." : "Continue with Google"}</span>
          </button>

          <p style={s.footer}>
            © 2026 New Era University Library · All rights reserved
          </p>
        </div>
      </div>

      {/* SCHEDULE MODAL */}
      {showSchedule && (
        <div style={s.modalBg} onClick={() => setShowSchedule(false)}>
          <div style={s.modalBox} onClick={(e) => e.stopPropagation()}>
            <div style={s.modalHead}>
              <h3 style={s.modalTitle}>📅 Library Schedule</h3>
              <button
                style={s.modalClose}
                onClick={() => setShowSchedule(false)}
              >
                ✕
              </button>
            </div>

            <img src={SCHEDULE_IMG} alt="Schedule" style={s.schedImg} />
          </div>
        </div>
      )}
    </div>
  );
}

const s = {
  page: {
    display: "flex",
    minHeight: "100vh",
    fontFamily: "'Plus Jakarta Sans', sans-serif",
    background: "#f8f5f0",
  },

  hero: { flex: 1.1, position: "relative", overflow: "hidden" },

  heroImg: {
    position: "absolute",
    inset: 0,
    width: "100%",
    height: "100%",
    objectFit: "cover",
  },

  heroOverlay: {
    position: "absolute",
    inset: 0,
    background:
      "linear-gradient(160deg, rgba(26,58,92,0.75) 0%, rgba(10,30,55,0.88) 100%)",
  },

  clock: {
    position: "absolute",
    top: "50%",
    left: "50%",
    transform: "translate(-50%, -50%)",
    textAlign: "center",
    color: "#fff",
  },

  clockTime: { fontSize: 72, fontWeight: 600 },

  clockDate: { fontSize: 14 },

  formSide: {
    flex: 1,
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    padding: "48px",
  },

  formWrap: { width: "100%", maxWidth: 420 },

  logoRow: { display: "flex", alignItems: "center", gap: 14, marginBottom: 36 },

  logoBox: {
    width: 52,
    height: 52,
    borderRadius: 14,
    overflow: "hidden",
  },

  logoLabel: { fontSize: 10, fontWeight: 700 },

  logoSub: { fontSize: 14 },

  title: { fontSize: 42, fontWeight: 700 },

  subtitle: { fontSize: 14, marginBottom: 20 },

  googleBtn: {
    width: "100%",
    padding: "14px",
    background: "#1a3a5c",
    border: "none",
    borderRadius: 12,
    color: "#fff",
    fontSize: 15,
    fontWeight: 600,
    cursor: "pointer",
  },

  googleBtnLoading: { opacity: 0.7 },

  footer: { fontSize: 11, textAlign: "center", marginTop: 20 },

  modalBg: {
